#include <bits/stdc++.h>
using namespace std;
const int mod=1145141,N=1e6+6;
int n,q,a[N],t[4*N],ans;
void build(int p,int l,int r){
    if(l==r){
        t[p]=a[l];
        return;
    }
    int mid=l+r>>1;
    build(p*2,l,mid);
    build(p*2+1,mid+1,r);
    t[p]=1LL*t[p*2]*t[p*2+1]%mod;
}
int query(int p,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[p];
    int mid=l+r>>1;
    long long ans=1;
    if(x<=mid)
        ans*=query(p*2,l,mid,x,y),ans%=mod;
    if(y>mid)
        ans*=query(p*2+1,mid+1,r,x,y),ans%=mod;
    return ans;
}
int main(){
    scanf("%d%d",&n,&q);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    build(1,1,n);
    while(q--){
        int l,r;
        scanf("%d%d",&l,&r);
        ans^=query(1,1,n,l,r);
    }
    printf("%d",ans);
    return 0;
}
